@import url('https://fonts.googleapis.com/css2?family=Outfit:wght@400;500;600;700;800;900&display=swap');

/* ── Full-page wrapper with blurple gradient ── */
.wrapper {
  min-height: 100vh;
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 2rem 1.5rem;
  background: linear-gradient(135deg,
      #2c2078 0%,
      #3a2a9e 25%,
      #5865f2 55%,
      #4752c4 80%,
      #2c2078 100%);
  font-family: 'Outfit', 'Helvetica Neue', Arial, sans-serif;
  position: relative;
  overflow: hidden;
}

/* ── Star field ── */
.starField {
  position: absolute;
  inset: 0;
  pointer-events: none;
  z-index: 0;
}

.star {
  position: absolute;
  background: #fff;
  border-radius: 50%;
  opacity: 0;
  animation: twinkle 3s ease-in-out infinite;
}

@keyframes twinkle {

  0%,
  100% {
    opacity: 0;
    transform: scale(0.5);
  }

  50% {
    opacity: 0.7;
    transform: scale(1);
  }
}

/* ── Frosted glass card ── */
.card {
  width: 100%;
  max-width: 440px;
  background: rgba(30, 31, 34, 0.85);
  backdrop-filter: blur(20px);
  -webkit-backdrop-filter: blur(20px);
  border: 1px solid rgba(255, 255, 255, 0.08);
  border-radius: 16px;
  padding: 2.5rem 2.5rem 2rem;
  box-shadow:
    0 20px 60px rgba(0, 0, 0, 0.4),
    0 0 0 1px rgba(255, 255, 255, 0.04) inset;
  position: relative;
  z-index: 1;
  animation: cardIn 0.5s ease forwards;
}

@keyframes cardIn {
  from {
    opacity: 0;
    transform: translateY(20px) scale(0.97);
  }

  to {
    opacity: 1;
    transform: translateY(0) scale(1);
  }
}

/* ── Branding ── */
.brandMark {
  font-size: 1.8rem;
  color: #5865f2;
  margin-bottom: 0.5rem;
  display: block;
  text-align: center;
  filter: drop-shadow(0 0 12px rgba(88, 101, 242, 0.4));
}

.title {
  font-weight: 800;
  font-size: 1.5rem;
  color: #fff;
  margin-bottom: 0.3rem;
  text-align: center;
  letter-spacing: -0.02em;
}

.subtitle {
  color: rgba(255, 255, 255, 0.55);
  font-size: 0.88rem;
  margin-bottom: 1.6rem;
  text-align: center;
  font-weight: 400;
}

/* ── Form ── */
.form {
  display: flex;
  flex-direction: column;
  gap: 1rem;
}

.field {
  display: flex;
  flex-direction: column;
  gap: 0.4rem;
}

.label {
  font-size: 0.7rem;
  font-weight: 700;
  color: rgba(255, 255, 255, 0.6);
  text-transform: uppercase;
  letter-spacing: 0.1em;
}

.input {
  background: rgba(0, 0, 0, 0.25);
  border: 1px solid rgba(255, 255, 255, 0.08);
  border-radius: 8px;
  padding: 0.75rem 1rem;
  color: #fff;
  font-size: 0.92rem;
  font-family: inherit;
  font-weight: 400;
  transition: border-color 0.2s, box-shadow 0.2s, background 0.2s;
  outline: none;
  width: 100%;
  box-sizing: border-box;
}

.input:focus {
  border-color: #5865f2;
  box-shadow: 0 0 0 3px rgba(88, 101, 242, 0.25);
  background: rgba(0, 0, 0, 0.35);
}

.input::placeholder {
  color: rgba(255, 255, 255, 0.25);
}

/* ── Error message ── */
.errorBox {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  padding: 0.7rem 1rem;
  background: rgba(237, 66, 69, 0.12);
  border: 1px solid rgba(237, 66, 69, 0.3);
  border-radius: 8px;
  color: #f38688;
  font-size: 0.82rem;
  font-weight: 500;
  animation: shakeIn 0.4s ease;
}

.errorIcon {
  font-size: 1rem;
  flex-shrink: 0;
}

@keyframes shakeIn {

  0%,
  100% {
    transform: translateX(0);
  }

  20% {
    transform: translateX(-6px);
  }

  40% {
    transform: translateX(6px);
  }

  60% {
    transform: translateX(-4px);
  }

  80% {
    transform: translateX(4px);
  }
}

/* ── Submit button ── */
.submitBtn {
  margin-top: 0.5rem;
  padding: 0.8rem;
  background: #5865f2;
  color: #fff;
  border: none;
  border-radius: 8px;
  font-size: 0.95rem;
  font-weight: 600;
  font-family: inherit;
  cursor: pointer;
  transition: background 0.2s, transform 0.15s, box-shadow 0.2s;
  width: 100%;
  position: relative;
  box-shadow: 0 4px 15px rgba(88, 101, 242, 0.3);
}

.submitBtn:hover:not(:disabled) {
  background: #4752c4;
  transform: translateY(-2px);
  box-shadow: 0 6px 20px rgba(88, 101, 242, 0.4);
}

.submitBtn:active:not(:disabled) {
  transform: translateY(0);
}

.submitBtn:disabled {
  opacity: 0.7;
  cursor: not-allowed;
}

/* loading spinner */
.spinner {
  display: inline-block;
  width: 16px;
  height: 16px;
  border: 2px solid rgba(255, 255, 255, 0.3);
  border-top-color: #fff;
  border-radius: 50%;
  animation: spin 0.6s linear infinite;
  vertical-align: middle;
  margin-right: 0.4rem;
}

@keyframes spin {
  to {
    transform: rotate(360deg);
  }
}

/* ── Divider ── */
.divider {
  height: 1px;
  background: rgba(255, 255, 255, 0.06);
  margin: 1.5rem 0;
}

/* ── Footer link ── */
.footer {
  text-align: center;
  font-size: 0.84rem;
  color: rgba(255, 255, 255, 0.4);
}

.footerLink {
  color: #00a8fc;
  font-weight: 500;
  text-decoration: none;
  transition: color 0.15s;
}

.footerLink:hover {
  text-decoration: underline;
  color: #00c8ff;
}

/* ── Responsive ── */
@media (max-width: 520px) {
  .card {
    padding: 2rem 1.5rem 1.5rem;
    border-radius: 12px;
  }

  .title {
    font-size: 1.3rem;
  }
}

/* ── OAuth Section ── */
.oauthSection {
  margin-top: 1.2rem;
}

.oauthDivider {
  display: flex;
  align-items: center;
  gap: 0.8rem;
  margin-bottom: 1.2rem;
}

.oauthDivider::before,
.oauthDivider::after {
  content: '';
  flex: 1;
  height: 1px;
  background: rgba(255, 255, 255, 0.08);
}

.oauthDivider span {
  color: rgba(255, 255, 255, 0.35);
  font-size: 0.78rem;
  font-weight: 500;
  text-transform: uppercase;
  letter-spacing: 0.08em;
}

.googleBtn {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 0.7rem;
  width: 100%;
  padding: 0.75rem 1rem;
  background: #ffffff;
  color: #3c4043;
  border: none;
  border-radius: 8px;
  font-size: 0.92rem;
  font-weight: 600;
  font-family: inherit;
  cursor: pointer;
  transition: background 0.2s, transform 0.15s, box-shadow 0.2s;
  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.15);
}

.googleBtn:hover {
  background: #f1f3f4;
  transform: translateY(-2px);
  box-shadow: 0 4px 16px rgba(0, 0, 0, 0.2);
}

.googleBtn:active {
  transform: translateY(0);
  background: #e8eaed;
}

.googleIcon {
  flex-shrink: 0;
}

/* ═══════════════════════════════════════════════════════════════════════════
   LinkSphere — Create/Join Server Modal (Modern Minimalist)
   ═══════════════════════════════════════════════════════════════════════════ */

.overlay {
    position: fixed;
    inset: 0;
    background-color: rgba(0, 0, 0, 0.6);
    backdrop-filter: blur(4px);
    display: flex;
    justify-content: center;
    align-items: center;
    z-index: 1000;
}

.modal {
    background-color: #141820;
    width: 440px;
    max-width: 90%;
    border-radius: 16px;
    padding: 0;
    box-shadow: 0 16px 48px rgba(0, 0, 0, 0.5);
    border: 1px solid rgba(255, 255, 255, 0.06);
    position: relative;
    display: flex;
    flex-direction: column;
    overflow: hidden;
    font-family: 'Inter', system-ui, sans-serif;
}

.mainView,
.tellUsMoreView {
    padding: 24px;
}

.customizeView,
.joinView {
    display: flex;
    flex-direction: column;
    height: 100%;
}

.closeButton,
.closeBtn {
    position: absolute;
    top: 16px;
    right: 16px;
    background: none;
    border: none;
    cursor: pointer;
    color: #555a6e;
    padding: 4px;
    transition: color 0.15s;
    z-index: 10;
}

.closeButton:hover,
.closeBtn:hover {
    color: #e4e6eb;
}

.closeButton svg {
    width: 24px;
    height: 24px;
}

.header {
    text-align: center;
    margin-bottom: 24px;
    padding-top: 16px;
}

.customizeView .header,
.joinView .header {
    padding-left: 24px;
    padding-right: 24px;
}

.title {
    color: #e4e6eb;
    font-size: 22px;
    font-weight: 700;
    margin: 0 0 8px 0;
}

.subtitle {
    color: #8b8fa3;
    font-size: 14px;
    margin: 0;
    line-height: 1.4;
}

.description {
    color: #8b8fa3;
    font-size: 14px;
    margin: 0;
    line-height: 1.4;
}

.content {
    display: flex;
    flex-direction: column;
    gap: 8px;
}

/* Option Blocks */
.optionBlock,
.tellUsOptionBlock {
    background-color: #0d1017;
    border: 1px solid rgba(255, 255, 255, 0.06);
    border-radius: 10px;
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 14px 16px;
    cursor: pointer;
    width: 100%;
    transition: all 0.15s;
    font-family: inherit;
}

.tellUsOptionBlock {
    padding: 16px;
    margin-top: 8px;
}

.optionBlock:hover,
.tellUsOptionBlock:hover {
    background-color: #1f2538;
    border-color: rgba(255, 255, 255, 0.1);
}

.optionBlockMain {
    display: flex;
    align-items: center;
    gap: 12px;
}

.optionIcon {
    width: 24px;
    height: 24px;
    color: #e4e6eb;
}

.optionEmoji {
    font-size: 20px;
}

.couchCtn,
.earthCtn {
    width: 24px;
    height: 24px;
    color: #e4e6eb;
    flex-shrink: 0;
}

.optionLabel {
    color: #e4e6eb;
    font-size: 14px;
    font-weight: 600;
}

.arrowIcon {
    width: 20px;
    height: 20px;
    color: #555a6e;
}

.sectionHeading {
    color: #555a6e;
    font-size: 10px;
    font-weight: 700;
    margin: 16px 0 0 0;
    text-transform: uppercase;
    letter-spacing: 0.08em;
}

/* Join section */
.joinSection {
    background-color: #0d1017;
    border: 1px solid rgba(255, 255, 255, 0.06);
    border-radius: 10px;
    padding: 16px;
    text-align: center;
    margin-top: 16px;
}

.joinHeading {
    color: #e4e6eb;
    font-size: 15px;
    font-weight: 600;
    margin: 0 0 10px 0;
}

.joinMenuButton {
    background: linear-gradient(135deg, #7c3aed, #3b82f6);
    border: none;
    border-radius: 8px;
    color: #fff;
    padding: 10px 20px;
    font-size: 13px;
    font-weight: 600;
    cursor: pointer;
    width: 100%;
    font-family: inherit;
    transition: all 0.2s;
}

.joinMenuButton:hover {
    transform: translateY(-1px);
    box-shadow: 0 4px 16px rgba(124, 58, 237, 0.4);
}

/* Tell us more */
.skipDesc {
    text-align: center;
    margin-top: 24px;
    margin-bottom: 0;
    color: #8b8fa3;
    font-size: 13px;
}

.skipLink {
    color: #7c3aed;
    font-weight: 600;
    cursor: pointer;
}

.skipLink:hover {
    text-decoration: underline;
}

/* Inputs */
.inputGroup {
    width: 100%;
    margin-bottom: 16px;
}

.inputLabel {
    display: block;
    color: #8b8fa3;
    font-size: 10px;
    font-weight: 700;
    text-transform: uppercase;
    letter-spacing: 0.06em;
    margin-bottom: 8px;
}

.nameInput,
.inputField {
    width: 100%;
    background-color: #0d1017;
    border: 1px solid rgba(255, 255, 255, 0.06);
    color: #e4e6eb;
    border-radius: 10px;
    padding: 12px 14px;
    font-size: 14px;
    outline: none;
    box-sizing: border-box;
    font-family: inherit;
    transition: border-color 0.2s, box-shadow 0.2s;
}

.nameInput:focus,
.inputField:focus {
    border-color: #7c3aed;
    box-shadow: 0 0 0 3px rgba(124, 58, 237, 0.15);
}

.asterisk {
    color: #ef4444;
}

/* Customize */
.contentCustomize {
    padding: 0 24px 24px 24px;
    display: flex;
    flex-direction: column;
    align-items: center;
}

.avatarUpload {
    width: 80px;
    height: 80px;
    border-radius: 18px;
    border: 2px dashed #555a6e;
    background: transparent;
    color: #e4e6eb;
    display: flex;
    justify-content: center;
    align-items: center;
    cursor: pointer;
    transition: border-color 0.15s;
    overflow: hidden;
    margin-bottom: 24px;
}

.avatarUpload:hover {
    border-color: #7c3aed;
}

.avatarPreview {
    width: 100%;
    height: 100%;
    object-fit: cover;
}

.uploadInner {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 4px;
}

.uploadInner svg {
    width: 32px;
    height: 32px;
    color: #8b8fa3;
}

.uploadInner span {
    font-size: 10px;
    font-weight: 700;
    color: #8b8fa3;
}

.hiddenInput {
    display: none;
}

.legalNote {
    font-size: 11px;
    color: #555a6e;
    line-height: 1.4;
    margin: 0;
    width: 100%;
}

.blueLink {
    color: #7c3aed;
    cursor: pointer;
}

.blueLink:hover {
    text-decoration: underline;
}

/* Join view */
.joinContentWrapper {
    padding: 0 24px 24px 24px;
}

.examplesSection {
    margin-bottom: 24px;
}

.examplesTitle {
    color: #8b8fa3;
    font-size: 11px;
    font-weight: 500;
    margin: 0 0 8px 0;
}

.tagsContainer {
    display: flex;
    flex-wrap: wrap;
    gap: 8px;
}

.tag {
    background-color: #0d1017;
    color: #8b8fa3;
    padding: 5px 10px;
    border-radius: 8px;
    font-size: 12px;
    border: 1px solid rgba(255, 255, 255, 0.06);
}

.discoverBlock {
    background-color: #0d1017;
    border-radius: 10px;
    padding: 12px 16px;
    display: flex;
    align-items: center;
    gap: 12px;
    cursor: pointer;
    border: 1px solid rgba(255, 255, 255, 0.06);
    transition: all 0.15s;
}

.discoverBlock:hover {
    background-color: #1f2538;
    border-color: rgba(255, 255, 255, 0.1);
}

.discoverIconWrapper {
    background: linear-gradient(135deg, #7c3aed, #3b82f6);
    border-radius: 10px;
    width: 40px;
    height: 40px;
    display: flex;
    align-items: center;
    justify-content: center;
    flex-shrink: 0;
}

.discoverTextContainer {
    flex: 1;
}

.discoverTitle {
    color: #e4e6eb;
    font-weight: 600;
    font-size: 14px;
    margin-bottom: 2px;
}

.discoverSubtitle {
    color: #8b8fa3;
    font-size: 12px;
    line-height: 1.3;
}

/* Footers */
.footerOnlyBack {
    padding-top: 24px;
    display: flex;
    justify-content: flex-start;
}

.footerWithFlex {
    padding: 16px 24px;
    background-color: #0d1017;
    border-top: 1px solid rgba(255, 255, 255, 0.06);
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-top: auto;
}

.backButton {
    background: transparent;
    border: none;
    color: #8b8fa3;
    font-size: 13px;
    font-weight: 500;
    cursor: pointer;
    padding: 0;
    font-family: inherit;
    transition: color 0.15s;
}

.backButton:hover {
    color: #e4e6eb;
}

.actionBtn,
.createBtn {
    background: linear-gradient(135deg, #7c3aed, #3b82f6);
    color: white;
    border: none;
    padding: 10px 24px;
    border-radius: 10px;
    font-size: 13px;
    font-weight: 600;
    font-family: inherit;
    cursor: pointer;
    transition: all 0.2s;
}

.actionBtn:hover,
.createBtn:hover {
    transform: translateY(-1px);
    box-shadow: 0 4px 16px rgba(124, 58, 237, 0.4);
}

.actionActive {
    cursor: pointer;
    opacity: 1;
}

.actionDisabled {
    cursor: not-allowed;
    opacity: 0.4;
}

.navbar {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 0 2rem;
  height: 56px;
  background: rgba(26, 17, 71, 0.6);
  backdrop-filter: blur(16px);
  -webkit-backdrop-filter: blur(16px);
  border-bottom: 1px solid rgba(255, 255, 255, 0.06);
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
  z-index: 100;
  transition: background 0.3s;
}

.logo {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  text-decoration: none;
  background: rgba(255, 255, 255, 0.08);
  padding: 0.35rem 0.9rem;
  border-radius: 20px;
  border: 1px solid rgba(255, 255, 255, 0.1);
  transition: background 0.15s;
}

.logo:hover {
  background: rgba(255, 255, 255, 0.12);
}

.logoIcon {
  font-size: 1.2rem;
  color: #5865f2;
}

.logoText {
  font-weight: 700;
  font-size: 0.95rem;
  color: #fff;
  letter-spacing: -0.01em;
}

.links {
  display: flex;
  align-items: center;
  gap: 0.5rem;
}

.loginBtn {
  padding: 0.45rem 1.2rem;
  border-radius: 20px;
  color: rgba(255, 255, 255, 0.8);
  font-size: 0.875rem;
  font-weight: 500;
  text-decoration: none;
  transition: color 0.15s, background 0.15s;
  background: rgba(255, 255, 255, 0.06);
  border: 1px solid rgba(255, 255, 255, 0.08);
}

.loginBtn:hover {
  color: #fff;
  background: rgba(255, 255, 255, 0.12);
}

.signupBtn {
  padding: 0.45rem 1.2rem;
  border-radius: 20px;
  background: #fff;
  color: #23272a;
  font-size: 0.875rem;
  font-weight: 600;
  text-decoration: none;
  transition: background 0.15s, transform 0.15s;
}

.signupBtn:hover {
  background: #f0f0f0;
  transform: translateY(-1px);
}
.navbar {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 1rem 2rem; 
  background-color: transparent; 
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  z-index: 100;
}

.logoLink {
  display: flex;
  align-items: center;
  transition: transform 0.2s ease;
}

.logoLink:hover {
  transform: scale(1.1); 
}

@import url('https://fonts.googleapis.com/css2?family=Noto+Sans:wght@300;400;500;600;700&display=swap');

*,
*::before,
*::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

:root {
  /* Discord-inspired palette */
  --bg: #313338;
  --surface: #2b2d31;
  --surface2: #1e1f22;
  --border: #3f4147;
  --accent: #5865f2;
  --accent-hover: #4752c4;
  --text: #f2f3f5;
  --text-muted: #b5bac1;
  --danger: #ed4245;
  --success: #23a55a;

  font-family: 'Noto Sans', 'Helvetica Neue', Arial, sans-serif;
}

body {
  background: var(--bg);
  color: var(--text);
  min-height: 100vh;
  margin: 0;
  font-size: 15px;
}

a {
  text-decoration: none;
  color: inherit;
}

button {
  cursor: pointer;
  font-family: inherit;
  border: none;
  outline: none;
}

input {
  font-family: inherit;
  outline: none;
  border: none;
}

/* ═══════════════════════════════════════════════════════════════════════════
   LinkSphere — Modern Minimalist Chat UI
   Design: Dark navy + glassmorphism + purple-blue gradient accents
   ═══════════════════════════════════════════════════════════════════════════ */

@import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700;800&display=swap');

:root {
  /* Palette */
  --bg-deep: #08090e;
  --bg-base: #0d1017;
  --bg-surface: #141820;
  --bg-raised: #1a1f2e;
  --bg-hover: #1f2538;
  --border: rgba(255, 255, 255, 0.06);
  --text-primary: #e4e6eb;
  --text-secondary: #8b8fa3;
  --text-muted: #555a6e;
  --accent-1: #7c3aed;
  --accent-2: #3b82f6;
  --accent-gradient: linear-gradient(135deg, #7c3aed, #3b82f6);
  --danger: #ef4444;
  --success: #22c55e;
  --glass: rgba(255, 255, 255, 0.03);
  --glass-border: rgba(255, 255, 255, 0.06);
}

/* ─── ROOT LAYOUT ─── */
.layout {
  display: flex;
  height: 100vh;
  background: var(--bg-deep);
  color: var(--text-primary);
  font-family: 'Inter', system-ui, -apple-system, sans-serif;
  overflow: hidden;
}

/* ═══════════════════════════════════════════
   1. SERVER BAR (far left)
   ═══════════════════════════════════════════ */
.serverSidebar {
  width: 68px;
  min-width: 68px;
  background: var(--bg-deep);
  display: flex;
  flex-direction: column;
  align-items: center;
  padding: 12px 0;
  gap: 8px;
  border-right: 1px solid var(--border);
}

.serverHome {
  width: 44px;
  height: 44px;
  border-radius: 14px;
  background: var(--bg-raised);
  display: flex;
  align-items: center;
  justify-content: center;
  color: var(--text-secondary);
  font-size: 1.2rem;
  cursor: pointer;
  border: 1px solid var(--glass-border);
  transition: all 0.25s cubic-bezier(0.4, 0, 0.2, 1);
}

.serverHome:hover {
  background: var(--accent-gradient);
  color: #fff;
  border-color: transparent;
  transform: translateY(-2px);
  box-shadow: 0 4px 20px rgba(124, 58, 237, 0.3);
}

.activeHome {
  background: var(--accent-gradient);
  color: #fff;
  border-color: transparent;
  box-shadow: 0 4px 20px rgba(124, 58, 237, 0.3);
}

.divider {
  width: 28px;
  height: 2px;
  background: var(--border);
  margin: 4px 0;
  border-radius: 1px;
}

/* --- UPDATED SERVER ICON LOGIC --- */
.serverIcon {
  width: 44px;
  height: 44px;
  border-radius: 14px;
  display: flex;
  align-items: center;
  justify-content: center;
  color: white;
  font-weight: 700;
  font-size: 0.95rem;
  border: 1px solid var(--glass-border);
  cursor: pointer;
  transition: all 0.25s cubic-bezier(0.4, 0, 0.2, 1);
  overflow: hidden;
}

.serverIcon:hover {
  border-color: rgba(255, 255, 255, 0.4);
  transform: translateY(-2px);
  box-shadow: 0 4px 15px rgba(0, 0, 0, 0.4);
}

.activeServer {
  border-radius: 12px;
  border-color: white;
  box-shadow: 0 0 15px rgba(255, 255, 255, 0.1);
}

/* ═══════════════════════════════════════════
   2. SECONDARY SIDEBAR (channels / DMs)
   ═══════════════════════════════════════════ */
.secondarySidebar {
  width: 240px;
  min-width: 240px;
  background: var(--bg-base);
  display: flex;
  flex-direction: column;
  border-right: 1px solid var(--border);
}

.serverHeader {
  padding: 16px 16px;
  font-weight: 700;
  font-size: 14px;
  letter-spacing: 0.01em;
  color: var(--text-primary);
  border-bottom: 1px solid var(--border);
  display: flex;
  justify-content: space-between;
  align-items: center;
  cursor: pointer;
  transition: background 0.15s;
  height: 52px;
}

.serverHeader:hover {
  background: var(--bg-hover);
}

.scrollSection {
  flex: 1;
  padding: 12px 8px;
  overflow-y: auto;
}

.scrollSection::-webkit-scrollbar {
  width: 4px;
}

.scrollSection::-webkit-scrollbar-thumb {
  background: var(--text-muted);
  border-radius: 2px;
}

.scrollSection::-webkit-scrollbar-track {
  background: transparent;
}

.categoryHeader {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 16px 10px 6px;
  color: var(--text-muted);
  font-size: 10px;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 0.08em;
}

.channel {
  width: 100%;
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 8px 10px;
  border-radius: 8px;
  color: var(--text-secondary);
  border: none;
  background: transparent;
  cursor: pointer;
  margin-bottom: 2px;
  font-family: inherit;
  font-size: 14px;
  transition: all 0.15s;
}

.channelLeft {
  display: flex;
  align-items: center;
  gap: 8px;
  font-weight: 500;
}

.channel:hover {
  background: var(--bg-hover);
  color: var(--text-primary);
}

.activeChannel {
  background: var(--bg-hover);
  color: #fff;
}

.hash {
  color: var(--text-muted);
  font-size: 16px;
  font-weight: 500;
}

/* DM Sidebar */
.searchWrapper {
  padding: 12px;
  height: 52px;
  border-bottom: 1px solid var(--border);
}

.searchButton {
  width: 100%;
  height: 28px;
  background: var(--bg-surface);
  border-radius: 8px;
  border: 1px solid var(--border);
  color: var(--text-muted);
  font-size: 12px;
  text-align: left;
  padding: 0 10px;
  cursor: pointer;
  font-weight: 500;
  font-family: inherit;
  transition: border-color 0.15s;
}

.searchButton:hover {
  border-color: var(--text-muted);
}

.dmNavList {
  display: flex;
  flex-direction: column; gap: 2px;
  padding: 8px;
}

.navItem {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 8px 10px;
  border-radius: 8px;
  cursor: pointer;
  color: var(--text-secondary);
  font-weight: 500;
  font-size: 14px;
  transition: all 0.15s;
}

.navItem:hover {
  background: var(--bg-hover);
  color: var(--text-primary);
}

.activeNavItem {
  background: var(--bg-hover);
  color: #fff;
}

.dmSectionHeader {
  padding: 20px 14px 6px 14px;
  display: flex;
  justify-content: space-between;
  align-items: center;
  color: var(--text-muted);
  font-size: 10px;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 0.08em;
}

.addDmBtn {
  background: none;
  border: none;
  color: var(--text-muted);
  cursor: pointer;
  font-size: 16px;
  transition: color 0.15s;
}

.addDmBtn:hover {
  color: var(--text-primary);
}

.dmPlaceholder {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 6px 12px;
  margin: 1px 8px;
}

.dmAvatarGhost {
  width: 32px;
  height: 32px;
  border-radius: 10px;
  background: var(--bg-raised);
}

.dmNameGhost {
  width: 80px;
  height: 10px;
  border-radius: 5px;
  background: var(--bg-raised);
}

/* ═══════════════════════════════════════════
   USER INFO BAR
   ═══════════════════════════════════════════ */
.userInfo {
  padding: 8px 10px;
  display: flex;
  align-items: center;
  justify-content: space-between;
  background: var(--bg-deep);
  border-top: 1px solid var(--border);
}

.userLeft {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 4px;
  border-radius: 8px;
  cursor: pointer;
  transition: background 0.15s;
}

.userLeft:hover {
  background: var(--bg-hover);
}

.avatarWrapper {
  position: relative;
  width: 32px;
  height: 32px;
}

.userAvatar {
  width: 100%;
  height: 100%;
  border-radius: 10px;
  background: var(--accent-gradient);
  display: flex;
  align-items: center;
  justify-content: center;
  color: #fff;
  font-weight: 700;
  font-size: 0.75rem;
}

.statusIndicator {
  position: absolute;
  bottom: -1px;
  right: -1px;
  width: 12px;
  height: 12px;
  background: var(--success);
  border: 2.5px solid var(--bg-deep);
  border-radius: 50%;
}

.userText {
  display: flex;
  flex-direction: column; line-height: 1.2;
}

.userName {
  font-size: 13px;
  font-weight: 600;
  color: var(--text-primary);
}

.userStatus {
  font-size: 11px;
  color: var(--text-muted);
}

.userControls {
  display: flex;
  align-items: center;
  gap: 2px;
}

.userIconBtn {
  width: 30px;
  height: 30px;
  border-radius: 8px;
  border: none;
  display: flex;
  align-items: center;
  justify-content: center;
  background: transparent;
  color: var(--text-muted);
  cursor: pointer;
  transition: all 0.15s;
}

.userIconBtn:hover {
  background: var(--bg-hover);
  color: var(--text-primary);
}

.userIconBtnDanger {
  color: var(--danger);
}

/* ═══════════════════════════════════════════
   3. MAIN AREA (Interactive Background)
   ═══════════════════════════════════════════ */
.mainArea {
  flex: 1;
  display: flex;
  flex-direction: column;
  background: var(--bg-surface);
  position: relative; /* Contain absolute glow */
  overflow: hidden;
}

/* THE DISCORD-STYLE INTERACTIVE GLOW */
.dynamicGlow {
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  pointer-events: none; /* Allow clicks to pass to UI */
  z-index: 0;
  background: radial-gradient(
    600px circle at var(--mouse-x) var(--mouse-y),
    rgba(59, 130, 246, 0.08), /* Modern translucent blue */
    transparent 40%
  );
  transition: opacity 0.5s ease;
}

/* Ensure UI content sits above the light effect */
.topHeader, .chatLayout, .friendsLayout {
  position: relative;
  z-index: 1;
}

/* HEADER */
.topHeader {
  height: 52px;
  padding: 0 20px;
  border-bottom: 1px solid var(--border);
  display: flex;
  align-items: center;
  justify-content: space-between;
  background: var(--bg-base);
}

.headerLeft {
  display: flex;
  align-items: center;
  gap: 16px;
}

.headerTitle {
  font-weight: 600;
  font-size: 15px;
  color: var(--text-primary);
  display: flex;
  align-items: center;
  gap: 8px;
}

.headerDivider {
  width: 1px;
  height: 20px;
  background: var(--border);
}

.headerTabs {
  display: flex;
  align-items: center;
  gap: 4px;
}

.tabBtn {
  background: transparent;
  border: none;
  color: var(--text-secondary);
  font-size: 13px;
  font-weight: 500;
  cursor: pointer;
  padding: 6px 12px;
  border-radius: 6px;
  font-family: inherit;
  transition: all 0.15s;
}

.tabBtn:hover {
  background: var(--bg-hover);
  color: var(--text-primary);
}

.activeTabBtn {
  background: var(--accent-gradient);
  color: #fff;
}

.activeTabBtn:hover {
  background: var(--accent-gradient);
}

.headerRight {
  display: flex;
  align-items: center;
  gap: 8px;
  color: var(--text-muted);
}

.iconBtn {
  background: transparent;
  border: none;
  color: var(--text-muted);
  cursor: pointer;
  display: flex;
  align-items: center;
  padding: 6px;
  border-radius: 6px;
  transition: all 0.15s;
}

.iconBtn:hover {
  background: var(--bg-hover);
  color: var(--text-primary);
}

/* ═══════════════════════════════════════════
   FRIENDS CONTENT AREA
   ═══════════════════════════════════════════ */
.friendsLayout {
  display: flex;
  flex: 1;
  overflow: hidden;
}

.friendsMain {
  flex: 1;
  padding: 32px;
  display: flex;
  flex-direction: column;
  gap: 32px;
  overflow-y: auto;
}

.addFriendTitle {
  font-size: 14px;
  font-weight: 700;
  color: var(--text-primary);
  text-transform: uppercase;
  letter-spacing: 0.03em;
  margin-bottom: 8px;
}

.addFriendDesc {
  color: var(--text-secondary);
  font-size: 13px;
}

.addFriendInputBox {
  display: flex;
  align-items: center;
  background: var(--bg-deep);
  border-radius: 10px;
  padding: 8px 12px;
  border: 1px solid var(--border);
  margin-top: 16px;
  transition: border-color 0.2s;
}

.addFriendInputBox:focus-within {
  border-color: var(--accent-1);
}

.friendInput {
  flex: 1;
  background: transparent;
  border: none;
  color: var(--text-primary);
  font-size: 14px;
  outline: none;
  font-family: inherit;
}

.friendInput::placeholder {
  color: var(--text-muted);
}

.sendRequestBtn {
  background: var(--accent-gradient);
  color: #fff;
  border: none;
  padding: 8px 16px;
  border-radius: 8px;
  font-size: 13px;
  font-weight: 600;
  opacity: 0.4;
  cursor: not-allowed;
  font-family: inherit;
  transition: opacity 0.2s;
}

.sendRequestBtn.active {
  opacity: 1;
  cursor: pointer;
}

.otherPlaces {
  border-top: 1px solid var(--border);
  padding-top: 32px;
}

.discoverBtn {
  display: flex;
  align-items: center;
  justify-content: space-between;
  background: var(--bg-raised);
  border: 1px solid var(--border);
  padding: 12px 16px;
  border-radius: 10px;
  margin-top: 16px;
  cursor: pointer;
  color: var(--text-primary);
  width: fit-content;
  gap: 48px;
  transition: all 0.15s;
}

.discoverBtn:hover {
  background: var(--bg-hover);
  border-color: var(--text-muted);
}

.discoverLeft {
  display: flex;
  align-items: center;
  gap: 12px;
  font-weight: 500;
}

.discoverIcon {
  width: 32px;
  height: 32px;
  background: var(--accent-gradient);
  border-radius: 8px;
  display: flex;
  align-items: center;
  justify-content: center;
  color: #fff;
}

/* ACTIVE NOW SIDEBAR */
.activeNow {
  width: 320px;
  min-width: 320px;
  border-left: 1px solid var(--border);
  padding: 24px 16px;
  display: flex;
  flex-direction: column;
  background: var(--bg-base);
}

.activeNowTitle {
  font-size: 16px;
  font-weight: 700;
  color: var(--text-primary);
  margin-bottom: 20px;
}

.emptyActiveCard {
  background: var(--bg-raised);
  border-radius: 12px;
  padding: 20px;
  text-align: center;
  border: 1px solid var(--border);
}

.emptyActiveTitle {
  font-weight: 600;
  color: var(--text-primary);
  margin-bottom: 8px;
  font-size: 14px;
}

.emptyActiveText {
  color: var(--text-secondary);
  font-size: 13px;
  line-height: 1.5;
}

/* ═══════════════════════════════════════════
   CHAT LAYOUT
   ═══════════════════════════════════════════ */
.chatLayout {
  flex: 1;
  display: flex;
  overflow: hidden;
}

.chatArea {
  flex: 1;
  display: flex;
  flex-direction: column;
  min-width: 0;
}

.messageList {
  flex: 1;
  overflow-y: auto;
  padding: 20px;
  display: flex;
  flex-direction: column;
  gap: 6px;
}

.messageList::-webkit-scrollbar {
  width: 6px;
}

.messageList::-webkit-scrollbar-thumb {
  background: var(--text-muted);
  border-radius: 3px;
}

.messageList::-webkit-scrollbar-track {
  background: transparent;
}

/* Welcome */
.welcomeMsg {
  padding: 20px 0 28px;
  border-bottom: 1px solid var(--border);
  margin-bottom: 20px;
}

.welcomeHash {
  width: 56px;
  height: 56px;
  border-radius: 16px;
  background: var(--accent-gradient);
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 24px;
  color: #fff;
  font-weight: 700;
  margin-bottom: 12px;
}

.welcomeTitle {
  font-size: 24px;
  font-weight: 700;
  color: var(--text-primary);
  margin-bottom: 6px;
}

.welcomeDesc {
  color: var(--text-secondary);
  font-size: 14px;
}

/* Message bubble */
.message {
  display: flex;
  gap: 12px;
  padding: 10px 14px;
  border-radius: 12px;
  transition: background 0.15s;
}

.message:hover {
  background: var(--glass);
}

.msgAvatarCircle {
  width: 36px;
  height: 36px;
  border-radius: 10px;
  display: flex;
  align-items: center;
  justify-content: center;
  font-weight: 700;
  font-size: 0.75rem;
  color: #fff;
  flex-shrink: 0;
}

.msgContent {
  flex: 1;
  min-width: 0;
}

.msgHeader {
  display: flex;
  align-items: baseline;
  gap: 8px;
  margin-bottom: 3px;
}

.msgAuthor {
  font-weight: 600;
  font-size: 14px;
}

.msgTimestamp {
  font-size: 11px;
  color: var(--text-muted);
}

.msgBody {
  color: var(--text-secondary);
  font-size: 14px;
  line-height: 1.5;
  word-break: break-word;
}

.msgAttachmentWrap {
  margin-top: 8px;
}

.msgAttachment {
  max-width: 400px;
  max-height: 350px;
  border-radius: 8px;
  object-fit: contain;
  background: var(--bg-deep);
  border: 1px solid var(--border);
}

/* System message */
.systemMsg {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 6px 14px;
  color: var(--success);
  font-size: 13px;
  font-weight: 500;
  opacity: 0.8;
}

.systemMsg svg {
  flex-shrink: 0;
}

/* Chat input */
.chatInputContainer {
  display: flex;
  flex-direction: column;
  padding: 0 20px 20px;
}

.attachmentPreviewWrap {
  position: relative;
  background: var(--bg-raised);
  border: 1px solid var(--border);
  border-radius: 12px;
  padding: 12px;
  margin-bottom: 10px;
  width: max-content;
  max-width: 100%;
}

.attachmentPreviewImg {
  max-height: 150px;
  border-radius: 8px;
  object-fit: contain;
}

.cancelAttachmentBtn {
  position: absolute;
  top: -8px;
  right: -8px;
  background: var(--danger);
  color: #fff;
  border: none;
  width: 24px;
  height: 24px;
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  cursor: pointer;
  box-shadow: 0 2px 8px rgba(0,0,0,0.3);
  transition: transform 0.15s;
}

.cancelAttachmentBtn:hover {
  transform: scale(1.1);
}

.chatInputBar {
  display: flex;
  align-items: center;
  gap: 10px;
}

.addAttachmentBtn {
  width: 42px;
  height: 42px;
  border-radius: 12px;
  background: var(--bg-raised);
  border: 1px solid var(--border);
  color: var(--text-muted);
  display: flex;
  align-items: center;
  justify-content: center;
  cursor: pointer;
  transition: all 0.2s;
  flex-shrink: 0;
}

.addAttachmentBtn:hover {
  background: var(--bg-hover);
  color: var(--text-primary);
}

.addAttachmentBtn:disabled {
  opacity: 0.5;
  cursor: not-allowed;
}

.chatInput {
  flex: 1;
  background: var(--bg-raised);
  border: 1px solid var(--border);
  border-radius: 12px;
  padding: 12px 16px;
  color: var(--text-primary);
  font-size: 14px;
  font-family: inherit;
  outline: none;
  transition: border-color 0.2s, box-shadow 0.2s;
}

.chatInput::placeholder {
  color: var(--text-muted);
}

.chatInput:focus {
  border-color: var(--accent-1);
  box-shadow: 0 0 0 3px rgba(124, 58, 237, 0.15);
}

.sendBtn {
  width: 42px;
  height: 42px;
  border-radius: 12px;
  background: var(--accent-gradient);
  border: none;
  color: #fff;
  display: flex;
  align-items: center;
  justify-content: center;
  cursor: pointer;
  transition: all 0.2s;
  flex-shrink: 0;
}

.sendBtn:hover:not(:disabled) {
  transform: translateY(-1px);
  box-shadow: 0 4px 16px rgba(124, 58, 237, 0.4);
}

.sendBtn:disabled {
  opacity: 0.3;
  cursor: not-allowed;
}

/* ═══════════════════════════════════════════
   MEMBERS SIDEBAR
   ═══════════════════════════════════════════ */
.membersSidebar {
  width: 220px;
  min-width: 220px;
  background: var(--bg-base);
  border-left: 1px solid var(--border);
  padding: 16px 8px;
  overflow-y: auto;
}

.membersHeader {
  font-size: 10px;
  font-weight: 700;
  color: var(--text-muted);
  text-transform: uppercase;
  letter-spacing: 0.08em;
  padding: 0 8px 14px;
}

.memberItem {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 6px 8px;
  border-radius: 8px;
  cursor: pointer;
  transition: background 0.15s;
}

.memberItem:hover {
  background: var(--bg-hover);
}

.memberAvatarWrap {
  position: relative;
  width: 28px;
  height: 28px;
  flex-shrink: 0;
}

.memberAvatar {
  width: 100%;
  height: 100%;
  border-radius: 8px;
  display: flex;
  align-items: center;
  justify-content: center;
  font-weight: 700;
  font-size: 0.65rem;
  color: #fff;
}

.memberDot {
  position: absolute;
  bottom: -1px;
  right: -1px;
  width: 10px;
  height: 10px;
  background: var(--success);
  border: 2px solid var(--bg-base);
  border-radius: 50%;
}

.memberName {
  font-size: 13px;
  font-weight: 500;
  color: var(--text-secondary);
}

.ownerBadge {
  margin-left: auto;
  display: flex;
  align-items: center;
}

.memberCount {
  display: flex;
  align-items: center; gap: 4px;
  color: var(--text-muted);
  font-size: 13px;
  font-weight: 500;
}

/* ═══════════════════════════════════════════
   SERVER DROPDOWN
   ═══════════════════════════════════════════ */
.serverDropdown {
  background: var(--bg-deep);
  border-radius: 10px;
  padding: 6px;
  margin: 0 8px;
  border: 1px solid var(--border);
  box-shadow: 0 8px 32px rgba(0, 0, 0, 0.5);
  animation: dropIn 0.15s ease;
}

@keyframes dropIn {
  from {
    opacity: 0;
    transform: translateY(-4px);
  }

  to {
    opacity: 1;
    transform: translateY(0);
  }
}

.dropdownItem {
  width: 100%;
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 10px 12px;
  border-radius: 8px;
  border: none;
  background: transparent;
  color: var(--text-secondary);
  font-size: 13px;
  font-weight: 500;
  cursor: pointer;
  font-family: inherit;
  transition: all 0.12s;
}

.dropdownItem:hover {
  background: var(--accent-gradient);
  color: #fff;
}

.dropdownItem:hover svg {
  stroke: #fff;
}

.dropdownDanger {
  color: var(--danger);
}

.dropdownDanger:hover {
  background: var(--danger);
  color: #fff;
}

/* ═══════════════════════════════════════════
   TOAST
   ═══════════════════════════════════════════ */
.toast {
  position: fixed;
  bottom: 24px;
  left: 50%;
  transform: translateX(-50%);
  background: var(--accent-gradient);
  color: #fff;
  padding: 12px 28px;
  border-radius: 12px;
  font-size: 13px;
  font-weight: 600;
  box-shadow: 0 6px 24px rgba(124, 58, 237, 0.4);
  animation: toastSlide 0.3s ease;
  z-index: 1000;
}

@keyframes toastSlide {
  from {
    opacity: 0;
    transform: translateX(-50%) translateY(12px);
  }

  to {
    opacity: 1;
    transform: translateX(-50%) translateY(0);
  }
}

/* ═══════════════════════════════════════════
   BADGES
   ═══════════════════════════════════════════ */
.newBadge {
  background: var(--accent-gradient);
  color: #fff;
  font-size: 10px;
  font-weight: 700;
  padding: 2px 7px;
  border-radius: 10px;
  margin-left: auto;
}

.topActions {
  display: none;
}

.actionItem {
  display: none;
}

/* ═══════════════════════════════════════════
   USER PROFILE POPUP
   ═══════════════════════════════════════════ */
.userPopup {
  position: absolute;
  bottom: calc(100% + 8px);
  left: 0;
  width: 300px;
  background: var(--bg-raised);
  border: 1px solid var(--glass-border);
  border-radius: 16px;
  box-shadow: 0 16px 48px rgba(0, 0, 0, 0.6), 0 4px 16px rgba(0, 0, 0, 0.4);
  z-index: 999;
  animation: popupIn 0.18s cubic-bezier(0.4, 0, 0.2, 1);
}

@keyframes popupIn {
  from {
    opacity: 0;
    transform: translateY(8px) scale(0.97);
  }

  to {
    opacity: 1;
    transform: translateY(0) scale(1);
  }
}

.userPopupBanner {
  height: 80px;
  background: linear-gradient(135deg, #7c3aed 0%, #3b82f6 100%);
  position: relative;
}

.userPopupAvatar {
  position: absolute;
  bottom: -24px;
  left: 16px;
  width: 68px;
  height: 68px;
  border-radius: 50%;
  background: linear-gradient(135deg, #7c3aed, #3b82f6);
  border: 5px solid var(--bg-raised);
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 1.6rem;
  font-weight: 700;
  color: #fff;
}

.userPopupStatusDot {
  position: absolute;
  bottom: 2px;
  right: 2px;
  width: 16px;
  height: 16px;
  background: var(--success);
  border: 3px solid var(--bg-raised);
  border-radius: 50%;
}

.userPopupNames {
  padding: 36px 16px 12px;
  border-bottom: 1px solid var(--border);
}

.userPopupDisplayName {
  font-size: 18px;
  font-weight: 800;
  color: var(--text-primary);
  letter-spacing: -0.01em;
}

.userPopupUsername {
  font-size: 13px;
  color: var(--text-secondary);
  margin-top: 2px;
}

.userPopupActions {
  padding: 8px;
  display: flex;
  flex-direction: column;
  gap: 2px;
}

.userPopupItem {
  width: 100%;
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 10px 12px;
  border-radius: 10px;
  background: transparent;
  border: none;
  color: var(--text-primary);
  font-size: 14px;
  font-weight: 500;
  font-family: inherit;
  cursor: pointer;
  transition: background 0.15s;
  text-align: left;
}

.userPopupItem:hover {
  background: var(--bg-hover);
}

.userPopupItemMuted {
  color: var(--text-secondary);
}

.userPopupItemMuted:hover {
  background: var(--bg-hover);
  color: var(--text-primary);
}

.userPopupBadge {
  margin-left: 8px;
  background: var(--danger);
  color: #fff;
  font-size: 10px;
  font-weight: 700;
  padding: 2px 6px;
  border-radius: 4px;
  letter-spacing: 0.05em;
}

/* Status dots */
.statusDotOnline,
.statusDotIdle,
.statusDotDnd,
.statusDotInvisible {
  width: 10px;
  height: 10px;
  border-radius: 50%;
  flex-shrink: 0;
}

.statusDotOnline {
  background: #22c55e;
}

.statusDotIdle {
  background: #f59e0b;
}

.statusDotDnd {
  background: #ef4444;
}

.statusDotInvisible {
  background: var(--text-muted);
}

/* Status submenu */
.statusSubmenu {
  position: absolute;
  left: calc(100% + 6px);
  top: 0;
  width: 260px;
  background: var(--bg-raised);
  border: 1px solid var(--glass-border);
  border-radius: 12px;
  box-shadow: 0 12px 40px rgba(0, 0, 0, 0.6);
  padding: 6px;
  z-index: 1000;
  animation: popupIn 0.15s cubic-bezier(0.4, 0, 0.2, 1);
}

.statusSubmenuItem {
  width: 100%;
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 10px 12px;
  border-radius: 8px;
  background: transparent;
  border: none;
  color: var(--text-primary);
  font-size: 13px;
  font-weight: 500;
  font-family: inherit;
  cursor: pointer;
  transition: background 0.15s;
  text-align: left;
}

.statusSubmenuItem:hover {
  background: var(--bg-hover);
}

.statusActive {
  background: var(--bg-surface);
}

.statusSubmenuDesc {
  font-size: 11px;
  color: var(--text-muted);
  padding: 2px 12px 8px;
  line-height: 1.4;
}

/* Generic status dot — color set via inline style */
.statusDotBase {
  width: 10px;
  height: 10px;
  border-radius: 50%;
  flex-shrink: 0;
  display: inline-block;
}

/* Inline status panel (expands inside popup) */
.statusInlinePanel {
  background: var(--bg-surface);
  border-radius: 10px;
  border: 1px solid var(--border);
  overflow: hidden;
  margin: 2px 4px 4px;
}

.statusPanelItem {
  width: 100%;
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 11px 14px;
  background: transparent;
  border: none;
  border-bottom: 1px solid var(--border);
  color: var(--text-primary);
  font-size: 14px;
  font-weight: 500;
  font-family: inherit;
  cursor: pointer;
  transition: background 0.15s;
  text-align: left;
}

.statusPanelItem:last-child {
  border-bottom: none;
}

.statusPanelItem:hover {
  background: var(--bg-hover);
}

.statusPanelActive {
  background: var(--bg-raised);
}

.statusPanelText {
  display: flex;
  flex-direction: column;
  gap: 2px;
}

.statusPanelDesc {
  font-size: 11px;
  color: var(--text-muted);
  font-weight: 400;
}

/* ─── ADD CHANNEL STYLES ─── */

.addChannelBtn {
  background: none;
  border: none;
  color: var(--text-muted);
  font-size: 18px;
  cursor: pointer;
  transition: color 0.15s;
  padding: 0 4px;
  display: flex;
  align-items: center;
  justify-content: center;
}

.addChannelBtn:hover {
  color: var(--text-primary);
}

/* Simple Modal Styling */
.modalOverlay {
  position: fixed;
  top: 0;
  left: 0;
  width: 100vw;
  height: 100vh;
  background: rgba(0, 0, 0, 0.7);
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 2000;
}

.modalContent {
  background: var(--bg-surface);
  padding: 24px;
  border-radius: 12px;
  width: 400px;
  border: 1px solid var(--border);
  box-shadow: 0 8px 32px rgba(0, 0, 0, 0.5);
}

.modalContent h3 {
  margin-bottom: 16px;
  color: #fff;
  font-size: 20px;
  font-weight: 700;
}

.modalInput {
  width: 100%;
  padding: 12px;
  background: var(--bg-deep);
  border: 1px solid var(--border);
  border-radius: 8px;
  color: #fff;
  margin-bottom: 20px;
  outline: none;
  font-family: inherit;
  font-size: 14px;
}

.modalInput:focus {
  border-color: var(--accent-1);
}

.modalActions {
  display: flex;
  justify-content: flex-end;
  gap: 12px;
}

.modalActions button {
  padding: 10px 20px;
  border-radius: 8px;
  border: none;
  cursor: pointer;
  font-weight: 600;
  font-family: inherit;
  font-size: 14px;
  transition: all 0.2s;
}

.modalActions button[type="button"] {
  background: transparent;
  color: var(--text-primary);
}

.modalActions button[type="button"]:hover {
  text-decoration: underline;
}

.createBtn {
  background: var(--accent-gradient);
  color: #fff;
}

.createBtn:hover:not(:disabled) {
  transform: translateY(-1px);
  box-shadow: 0 4px 12px rgba(124, 58, 237, 0.3);
}

.createBtn:disabled {
  opacity: 0.5;
  cursor: not-allowed;
}

/* ─── NEW: DELETE CHANNEL STYLES ─── */

.channelRight {
  display: flex;
  align-items: center;
  opacity: 0; /* Hidden by default */
  transition: opacity 0.2s ease;
}

.channel:hover .channelRight {
  opacity: 1; /* Shows up when you hover the channel button */
}

.channelDeleteIcon {
  color: var(--text-muted);
  cursor: pointer;
  transition: all 0.2s;
  padding: 2px;
  border-radius: 4px;
}

.channelDeleteIcon:hover {
  color: var(--danger);
  background: rgba(239, 68, 68, 0.1);
  transform: scale(1.1);
}
@keyframes spin {
  100% {
    transform: rotate(360deg);
  }
}
.spinning {
  animation: spin 1s linear infinite;
}

/* ═══════════════════════════════════════════
   VOICE UI ELEMENTS
   ═══════════════════════════════════════════ */
.voiceChannelWrapper {
  display: flex;
  flex-direction: column;
}

.voiceUsersList {
  display: flex;
  flex-direction: column;
  padding: 2px 0 6px 32px;
  gap: 2px;
}

.voiceUserItem {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 4px 8px;
  border-radius: 4px;
  color: var(--text-secondary);
  font-size: 13px;
  font-weight: 500;
  transition: all 0.15s;
}

.voiceUserItem:hover {
  background: var(--bg-hover);
  color: var(--text-primary);
}

.voiceUserAvatar {
  width: 24px;
  height: 24px;
  border-radius: 50%;
  background: var(--accent-gradient);
  display: flex;
  align-items: center;
  justify-content: center;
  color: #fff;
  font-size: 10px;
  font-weight: bold;
  overflow: hidden;
}

.voiceUserAvatar img {
  width: 100%;
  height: 100%;
  object-fit: cover;
}

.voiceConnectedPanel {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 10px 14px;
  background: rgba(34, 197, 94, 0.05);
  border-top: 1px solid rgba(34, 197, 94, 0.2);
  margin-top: auto; /* Pushes it and UserInfoBar to the bottom */
}

.voiceStatusText {
  display: flex;
  flex-direction: column;
  gap: 2px;
}

.disconnectBtn {
  background: transparent;
  border: none;
  color: var(--text-muted);
  cursor: pointer;
  padding: 6px;
  border-radius: 6px;
  display: flex;
  align-items: center;
  justify-content: center;
  transition: all 0.15s;
}

.disconnectBtn:hover {
  background: var(--bg-hover);
  color: var(--danger);
}

@import url('https://fonts.googleapis.com/css2?family=Outfit:wght@400;500;600;700;800;900&display=swap');

/* ─────────────────────────────────────────
   PAGE SHELL
───────────────────────────────────────── */
.page {
  min-height: 100vh;
  display: flex;
  flex-direction: column;
  background: #1a1147;
  color: #dcddde;
  font-family: 'Outfit', 'Helvetica Neue', Arial, sans-serif;
  overflow-x: hidden;
}

/* ─────────────────────────────────────────
   HERO SECTION
───────────────────────────────────────── */
.hero {
  position: relative;
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 3rem;
  padding: 8rem 4rem 6rem;
  min-height: 100vh;
  background: linear-gradient(135deg,
      #2c2078 0%,
      #3a2a9e 25%,
      #5865f2 55%,
      #4752c4 80%,
      #2c2078 100%);
  overflow: hidden;
}

/* ── Twinkling Stars ── */
.starField {
  position: absolute;
  inset: 0;
  pointer-events: none;
  z-index: 0;
}

.star {
  position: absolute;
  background: #fff;
  border-radius: 50%;
  opacity: 0;
  animation: twinkle 3s ease-in-out infinite;
}

@keyframes twinkle {

  0%,
  100% {
    opacity: 0;
    transform: scale(0.5);
  }

  50% {
    opacity: 0.8;
    transform: scale(1);
  }
}

/* ── Hero Content (text side) ── */
.heroContent {
  position: relative;
  z-index: 2;
  max-width: 540px;
  flex-shrink: 0;
}

.heading {
  font-weight: 900;
  font-size: clamp(2.8rem, 5.5vw, 4.6rem);
  line-height: 1.05;
  letter-spacing: -0.02em;
  text-transform: uppercase;
  color: #ffffff;
  margin-bottom: 1.4rem;
  font-style: italic;
}

.sub {
  color: rgba(255, 255, 255, 0.8);
  font-size: 1.05rem;
  line-height: 1.7;
  font-weight: 400;
  margin-bottom: 2.5rem;
  font-style: italic;
  max-width: 460px;
}

.actions {
  display: flex;
  gap: 1rem;
  align-items: center;
  flex-wrap: wrap;
}

.primaryBtn {
  display: inline-flex;
  align-items: center;
  gap: 0.5rem;
  padding: 0.9rem 2rem;
  background: #fff;
  color: #23272a;
  border-radius: 28px;
  font-size: 0.95rem;
  font-weight: 600;
  text-decoration: none;
  transition: all 0.2s ease;
  box-shadow: 0 4px 20px rgba(0, 0, 0, 0.15);
}

.primaryBtn:hover {
  background: #f0f0f0;
  transform: translateY(-2px);
  box-shadow: 0 6px 24px rgba(0, 0, 0, 0.25);
}

.secondaryBtn {
  display: inline-flex;
  align-items: center;
  gap: 0.5rem;
  padding: 0.9rem 2rem;
  background: #23272a;
  color: #fff;
  border-radius: 28px;
  font-size: 0.95rem;
  font-weight: 600;
  text-decoration: none;
  transition: all 0.2s ease;
  box-shadow: 0 4px 20px rgba(0, 0, 0, 0.15);
}

.secondaryBtn:hover {
  background: #2d3136;
  transform: translateY(-2px);
  box-shadow: 0 6px 24px rgba(0, 0, 0, 0.25);
}

/* ── Hero Visual (mockup) ── */
.heroVisual {
  position: relative;
  z-index: 2;
  flex-shrink: 0;
}

.mockupWindow {
  width: 520px;
  background: #1e1f22;
  border-radius: 16px;
  overflow: hidden;
  box-shadow:
    0 20px 60px rgba(0, 0, 0, 0.4),
    0 0 0 1px rgba(255, 255, 255, 0.06);
  animation: floatMockup 6s ease-in-out infinite;
}

@keyframes floatMockup {

  0%,
  100% {
    transform: translateY(0px);
  }

  50% {
    transform: translateY(-12px);
  }
}

.mockupBar {
  display: flex;
  gap: 6px;
  padding: 12px 16px;
  background: #111214;
}

.dot {
  width: 10px;
  height: 10px;
  border-radius: 50%;
}

.mockupBody {
  display: flex;
  height: 340px;
}

/* sidebar icons */
.mockupSidebar {
  width: 60px;
  background: #111214;
  display: flex;
  flex-direction: column;
  align-items: center;
  padding: 8px 0;
  gap: 6px;
}

.serverIcon {
  width: 40px;
  height: 40px;
  border-radius: 14px;
  display: flex;
  align-items: center;
  justify-content: center;
  color: #fff;
  font-weight: 700;
  font-size: 0.7rem;
  transition: border-radius 0.2s;
  cursor: pointer;
}

.serverIcon:hover {
  border-radius: 10px;
}

/* channel list */
.mockupChannels {
  width: 180px;
  background: #2b2d31;
  border-right: 1px solid rgba(255, 255, 255, 0.04);
  padding: 12px 0;
}

.channelHeader {
  padding: 0 12px 10px;
  font-weight: 700;
  font-size: 0.85rem;
  color: #f2f3f5;
}

.channelItem {
  display: flex;
  align-items: center;
  gap: 6px;
  padding: 5px 12px;
  font-size: 0.8rem;
  color: #96989d;
  cursor: pointer;
  transition: background 0.15s, color 0.15s;
}

.channelItem:hover {
  background: rgba(255, 255, 255, 0.04);
  color: #dcddde;
}

.activeChannel {
  background: rgba(88, 101, 242, 0.12);
  color: #fff;
}

.hash {
  color: #96989d;
  font-weight: 600;
  font-size: 1rem;
}

.voiceIcon {
  font-size: 0.75rem;
}

/* chat area */
.mockupChat {
  flex: 1;
  padding: 12px 14px;
  display: flex;
  flex-direction: column;
  gap: 14px;
  overflow: hidden;
}

.chatMsg {
  display: flex;
  gap: 10px;
  animation: fadeInMsg 0.5s ease forwards;
  opacity: 0;
}

.chatMsg:nth-child(1) {
  animation-delay: 0.4s;
}

.chatMsg:nth-child(2) {
  animation-delay: 0.8s;
}

.chatMsg:nth-child(3) {
  animation-delay: 1.2s;
}

@keyframes fadeInMsg {
  from {
    opacity: 0;
    transform: translateY(8px);
  }

  to {
    opacity: 1;
    transform: translateY(0);
  }
}

.msgAvatar {
  width: 32px;
  height: 32px;
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  font-weight: 700;
  font-size: 0.72rem;
  color: #fff;
  flex-shrink: 0;
}

.msgName {
  font-weight: 600;
  font-size: 0.82rem;
  margin-right: 6px;
}

.msgTime {
  font-size: 0.62rem;
  color: #72767d;
}

.msgText {
  font-size: 0.78rem;
  color: #dcddde;
  margin-top: 2px;
  line-height: 1.4;
}

/* ─────────────────────────────────────────
   FEATURE SECTIONS
───────────────────────────────────────── */
.featureSection {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 4rem;
  padding: 6rem 4rem;
  position: relative;
  overflow: hidden;
}

/* gradient variants */
.purple {
  background: linear-gradient(150deg, #2c2078 0%, #3a2a9e 40%, #5865f2 100%);
}

.pink {
  background: linear-gradient(150deg, #3a2a9e 0%, #7c3aed 40%, #ec4899 100%);
}

.green {
  background: linear-gradient(150deg, #1a5c3a 0%, #059669 40%, #10b981 100%);
}

.blue {
  background: linear-gradient(150deg, #1e3a5f 0%, #1d4ed8 40%, #5865f2 100%);
}

.featureCard {
  position: relative;
  width: 460px;
  background: rgba(0, 0, 0, 0.25);
  border-radius: 24px;
  padding: 2rem;
  box-shadow: 0 20px 50px rgba(0, 0, 0, 0.3);
  border: 1px solid rgba(255, 255, 255, 0.08);
  flex-shrink: 0;
  backdrop-filter: blur(10px);
}

.featureCardIcon {
  position: absolute;
  top: -20px;
  right: -20px;
  width: 60px;
  height: 60px;
  background: rgba(255, 255, 255, 0.1);
  border-radius: 16px;
  display: flex;
  align-items: center;
  justify-content: center;
  border: 1px solid rgba(255, 255, 255, 0.15);
}

.featureIcon {
  width: 28px;
  height: 28px;
  color: #fff;
}

.featureText {
  max-width: 420px;
}

.featureTitle {
  font-size: clamp(2rem, 4vw, 3rem);
  font-weight: 900;
  text-transform: uppercase;
  color: #fff;
  line-height: 1.1;
  letter-spacing: -0.02em;
  margin-bottom: 1.2rem;
  font-style: italic;
}

.featureDesc {
  font-size: 1.05rem;
  line-height: 1.75;
  color: rgba(255, 255, 255, 0.75);
  font-style: italic;
}

/* ── Mini UI illustrations inside feature cards ── */

/* Purple – server/channels */
.miniServer {
  background: #2b2d31;
  border-radius: 12px;
  overflow: hidden;
}

.miniServerHeader {
  display: flex;
  align-items: center;
  gap: 6px;
  padding: 10px 14px;
  background: #1e1f22;
  font-size: 0.82rem;
  font-weight: 600;
  color: #f2f3f5;
}

.miniHash {
  color: #72767d;
  font-size: 1rem;
}

.miniChannelList {
  padding: 6px 0;
}

.miniChannel {
  padding: 5px 14px;
  font-size: 0.78rem;
  color: #96989d;
  cursor: pointer;
  transition: background 0.15s;
}

.miniChannel:hover {
  background: rgba(255, 255, 255, 0.04);
}

.miniActive {
  background: rgba(88, 101, 242, 0.12);
  color: #fff;
}

/* Pink – chat messages */
.miniChat {
  background: #2b2d31;
  border-radius: 12px;
  padding: 14px;
  display: flex;
  flex-direction: column;
  gap: 10px;
}

.miniChatBubble {
  display: flex;
  gap: 8px;
  align-items: flex-start;
}

.miniAvatar {
  width: 28px;
  height: 28px;
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 0.65rem;
  font-weight: 700;
  color: #fff;
  flex-shrink: 0;
}

.miniBubbleContent {
  display: flex;
  flex-direction: column;
  gap: 2px;
  font-size: 0.78rem;
  color: #dcddde;
}

.miniBubbleName {
  font-weight: 600;
  font-size: 0.75rem;
  color: #f2f3f5;
}

.miniTyping {
  display: flex;
  align-items: center;
  gap: 4px;
  padding-top: 4px;
}

.typingDot {
  width: 6px;
  height: 6px;
  background: #72767d;
  border-radius: 50%;
  animation: typingBounce 1.4s ease-in-out infinite;
}

.typingDot:nth-child(2) {
  animation-delay: 0.2s;
}

.typingDot:nth-child(3) {
  animation-delay: 0.4s;
}

@keyframes typingBounce {

  0%,
  60%,
  100% {
    transform: translateY(0);
  }

  30% {
    transform: translateY(-4px);
  }
}

.typingLabel {
  font-size: 0.7rem;
  color: #72767d;
  margin-left: 4px;
}

/* Green – online list */
.miniOnline {
  background: #2b2d31;
  border-radius: 12px;
  padding: 14px;
}

.miniOnlineHeader {
  font-size: 0.65rem;
  text-transform: uppercase;
  letter-spacing: 0.1em;
  font-weight: 700;
  color: #3ba55d;
  margin-bottom: 10px;
}

.miniUser {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 5px 0;
  font-size: 0.82rem;
  color: #dcddde;
}

.miniUserDot {
  width: 8px;
  height: 8px;
  border-radius: 50%;
  flex-shrink: 0;
}

.miniActivity {
  font-size: 0.7rem;
  color: #72767d;
  margin-left: auto;
}

/* Blue – roles */
.miniRoles {
  background: #2b2d31;
  border-radius: 12px;
  padding: 14px;
}

.miniRolesHeader {
  font-size: 0.82rem;
  font-weight: 700;
  color: #f2f3f5;
  margin-bottom: 12px;
}

.miniRole {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 6px 10px;
  font-size: 0.82rem;
  color: #dcddde;
  background: rgba(255, 255, 255, 0.04);
  border-radius: 6px;
  margin-bottom: 6px;
}

.miniRoleDot {
  width: 10px;
  height: 10px;
  border-radius: 50%;
  flex-shrink: 0;
}

.featureCardMock {
  margin-top: 0.5rem;
}

/* ─────────────────────────────────────────
   CTA SECTION
───────────────────────────────────────── */
.cta {
  position: relative;
  text-align: center;
  padding: 8rem 2rem;
  background: linear-gradient(180deg,
      #2c2078 0%,
      #3a2a9e 50%,
      #1a1147 100%);
  overflow: hidden;
}

.ctaStars {
  position: absolute;
  inset: 0;
  pointer-events: none;
}

.ctaHeading {
  font-weight: 900;
  font-size: clamp(2rem, 5vw, 3.5rem);
  text-transform: uppercase;
  color: #fff;
  margin-bottom: 1rem;
  position: relative;
  z-index: 1;
  letter-spacing: -0.02em;
  font-style: italic;
}

.ctaSub {
  font-size: 1.1rem;
  color: rgba(255, 255, 255, 0.7);
  margin-bottom: 2.5rem;
  position: relative;
  z-index: 1;
  font-style: italic;
}

.ctaButton {
  display: inline-flex;
  align-items: center;
  gap: 0.5rem;
  padding: 1rem 2.5rem;
  background: #5865f2;
  color: #fff;
  border-radius: 28px;
  font-size: 1rem;
  font-weight: 600;
  text-decoration: none;
  position: relative;
  z-index: 1;
  transition: all 0.2s ease;
  box-shadow: 0 4px 20px rgba(88, 101, 242, 0.4);
}

.ctaButton:hover {
  background: #4752c4;
  transform: translateY(-2px);
  box-shadow: 0 8px 30px rgba(88, 101, 242, 0.5);
}

/* ─────────────────────────────────────────
   FOOTER
───────────────────────────────────────── */
.footer {
  background: #1a1147;
  padding: 3rem 4rem 0;
  position: relative;
  overflow: hidden;
}

.footerInner {
  max-width: 1200px;
  margin: 0 auto;
  display: grid;
  grid-template-columns: 1.8fr 1fr 1fr 1.4fr;
  gap: 2.5rem;
  padding-bottom: 2rem;
}

.footerBrand {
  display: flex;
  flex-direction: column;
  gap: 0.6rem;
}

.footerLogo {
  font-weight: 800;
  font-size: 1.1rem;
  color: #fff;
  letter-spacing: -0.01em;
}

.footerTagline {
  font-size: 0.82rem;
  color: rgba(255, 255, 255, 0.5);
  line-height: 1.6;
  max-width: 280px;
}

.socialLinks {
  display: flex;
  gap: 1rem;
  margin-top: 0.5rem;
}

.socialLinks a {
  color: rgba(255, 255, 255, 0.5);
  transition: color 0.15s;
}

.socialLinks a:hover {
  color: #fff;
}

.footerCol {
  display: flex;
  flex-direction: column;
  gap: 0.3rem;
}

.footerColHeading {
  font-size: 0.68rem;
  text-transform: uppercase;
  letter-spacing: 0.12em;
  color: #5865f2;
  font-weight: 700;
  margin-bottom: 0.6rem;
}

.footerLinks {
  list-style: none;
  padding: 0;
  margin: 0;
  display: flex;
  flex-direction: column;
  gap: 0.4rem;
}

.footerLinks li {
  font-size: 0.82rem;
}

.footerLinks a,
.footerLinks span {
  color: rgba(255, 255, 255, 0.5);
  text-decoration: none;
  transition: color 0.15s;
}

.footerLinks a:hover {
  color: #fff;
}

.contributorLink {
  display: flex;
  align-items: center;
  gap: 0.5rem;
}

.contributorAvatar {
  width: 22px;
  height: 22px;
  border-radius: 50%;
  background: linear-gradient(135deg, #5865f2, #4752c4);
  color: #fff;
  font-size: 0.55rem;
  font-weight: 700;
  display: flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
}

/* Giant Wordmark */
.footerWordmark {
  font-size: clamp(10rem, 18vw, 16rem);
  font-weight: 900;
  color: rgba(88, 101, 242, 0.08);
  text-align: center;
  line-height: 0.85;
  letter-spacing: -0.04em;
  padding: 1rem 0;
  user-select: none;
  pointer-events: none;
}

.footerBottom {
  border-top: 1px solid rgba(255, 255, 255, 0.06);
  padding: 1rem 0;
  max-width: 1200px;
  margin: 0 auto;
}

.footerBottom p {
  font-size: 0.72rem;
  color: rgba(255, 255, 255, 0.35);
  text-align: center;
}

/* ─────────────────────────────────────────
   RESPONSIVE
───────────────────────────────────────── */
@media (max-width: 1024px) {
  .hero {
    flex-direction: column;
    padding: 7rem 2rem 4rem;
    text-align: center;
    min-height: auto;
  }

  .heroContent {
    align-items: center;
    display: flex;
    flex-direction: column;
  }

  .actions {
    justify-content: center;
  }

  .mockupWindow {
    width: 100%;
    max-width: 480px;
  }

  .featureSection {
    flex-direction: column !important;
    padding: 4rem 2rem;
    gap: 2.5rem;
    text-align: center;
  }

  .featureCard {
    width: 100%;
    max-width: 420px;
  }

  .featureText {
    max-width: 100%;
  }

  .footerInner {
    grid-template-columns: 1fr 1fr;
  }
}

@media (max-width: 640px) {
  .hero {
    padding: 6rem 1.5rem 3rem;
  }

  .heading {
    font-size: 2.2rem;
  }

  .sub {
    font-size: 0.92rem;
  }

  .actions {
    flex-direction: column;
    width: 100%;
  }

  .primaryBtn,
  .secondaryBtn {
    width: 100%;
    justify-content: center;
  }

  .mockupBody {
    height: 280px;
  }

  .mockupChannels {
    width: 140px;
  }

  .featureSection {
    padding: 3rem 1.5rem;
  }

  .featureCard {
    padding: 1.5rem;
  }

  .footerInner {
    grid-template-columns: 1fr;
    gap: 1.5rem;
  }

  .footer {
    padding: 2rem 1.5rem 0;
  }

  .footerWordmark {
    font-size: 4rem;
  }

}

/* ═══════════════════════════════════════════════════════════════════════════
   LinkSphere — Settings Panel (Modern Minimalist)
   ═══════════════════════════════════════════════════════════════════════════ */

@import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700;800&display=swap');

.overlay {
  position: fixed;
  inset: 0;
  display: flex;
  z-index: 1000;
  animation: fadeIn 0.25s ease-out;
  font-family: 'Inter', system-ui, -apple-system, sans-serif;
  color: #e4e6eb;
}

@keyframes fadeIn {
  from {
    opacity: 0;
  }

  to {
    opacity: 1;
  }
}

/* LEFT SIDEBAR */
.sidebar {
  flex: 1 0 250px;
  background: #0d1017;
  display: flex;
  justify-content: flex-end;
}

.sidebarContent {
  width: 250px;
  padding: 60px 10px 60px 20px;
  overflow-y: auto;
  display: flex;
  flex-direction: column;
}

.sidebarContent::-webkit-scrollbar {
  width: 4px;
}

.sidebarContent::-webkit-scrollbar-thumb {
  background: #555a6e;
  border-radius: 2px;
}

/* Profile snippet */
.profileSnippet {
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 8px 10px;
  margin-bottom: 12px;
}

.snippetAvatar {
  width: 34px;
  height: 34px;
  border-radius: 10px;
  background: linear-gradient(135deg, #7c3aed, #3b82f6);
  display: flex;
  align-items: center;
  justify-content: center;
  color: #fff;
  font-size: 14px;
  font-weight: 700;
}

.snippetInfo {
  display: flex;
  flex-direction: column;
}

.snippetName {
  font-size: 14px;
  font-weight: 600;
  color: #e4e6eb;
  display: flex;
  align-items: center;
  gap: 6px;
}

.newBadge {
  background: linear-gradient(135deg, #7c3aed, #3b82f6);
  color: #fff;
  font-size: 9px;
  font-weight: 800;
  padding: 2px 5px;
  border-radius: 6px;
}

.editProfileLink {
  font-size: 11px;
  color: #8b8fa3;
  display: flex;
  align-items: center;
  gap: 4px;
  cursor: pointer;
  transition: color 0.15s;
}

.editProfileLink:hover {
  color: #e4e6eb;
}

/* Search */
.searchBox {
  background: #141820;
  border-radius: 8px;
  padding: 7px 10px;
  display: flex;
  align-items: center;
  gap: 8px;
  margin-bottom: 16px;
  border: 1px solid rgba(255, 255, 255, 0.06);
  transition: border-color 0.15s;
}

.searchBox:focus-within {
  border-color: #7c3aed;
}

.searchBox input {
  background: transparent;
  border: none;
  color: #e4e6eb;
  font-size: 13px;
  outline: none;
  width: 100%;
  font-family: inherit;
}

.searchBox input::placeholder {
  color: #555a6e;
}

/* Nav */
.navSection {
  margin-bottom: 12px;
}

.navHeader {
  padding: 6px 10px;
  font-size: 10px;
  font-weight: 700;
  color: #555a6e;
  text-transform: uppercase;
  letter-spacing: 0.08em;
  margin-bottom: 4px;
}

.navItem {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 8px 10px;
  color: #8b8fa3;
  font-size: 14px;
  font-weight: 500;
  border-radius: 8px;
  cursor: pointer;
  margin-bottom: 1px;
  transition: all 0.12s;
}

.navItem:hover {
  background: #1f2538;
  color: #e4e6eb;
}

.activeNavItem {
  background: #1f2538;
  color: #fff;
}

.logoutItem {
  color: #ef4444;
}

.logoutItem:hover {
  background: rgba(239, 68, 68, 0.1);
  color: #ef4444;
}

.divider {
  height: 1px;
  background: rgba(255, 255, 255, 0.06);
  margin: 8px 10px;
}

/* RIGHT AREA */
.mainArea {
  flex: 2 0 400px;
  background: #141820;
  padding: 60px 40px;
  overflow-y: auto;
  position: relative;
}

.mainArea::-webkit-scrollbar {
  width: 6px;
}

.mainArea::-webkit-scrollbar-thumb {
  background: #555a6e;
  border-radius: 3px;
}

.contentWrapper {
  max-width: 700px;
  padding-bottom: 80px;
}

.pageTitle {
  font-size: 18px;
  font-weight: 700;
  color: #fff;
  margin-bottom: 24px;
}

/* Account Card */
.accountCard {
  background: #0d1017;
  border-radius: 14px;
  overflow: hidden;
  border: 1px solid rgba(255, 255, 255, 0.06);
}

.cardBanner {
  height: 90px;
  background: linear-gradient(135deg, #7c3aed, #3b82f6);
}

.cardHeader {
  display: flex;
  justify-content: space-between;
  align-items: flex-start;
  padding: 16px;
  position: relative;
}

.cardAvatarWrapper {
  position: absolute;
  top: -36px;
  left: 16px;
  width: 72px;
  height: 72px;
  border-radius: 18px;
  border: 5px solid #0d1017;
  overflow: hidden;
}

.cardUserInfo {
  margin-top: 32px;
  display: flex;
  align-items: center;
  gap: 8px;
}

.cardName {
  font-size: 18px;
  font-weight: 700;
  color: #e4e6eb;
}

.editProfileBtn {
  background: linear-gradient(135deg, #7c3aed, #3b82f6);
  color: #fff;
  border: none;
  padding: 8px 16px;
  border-radius: 8px;
  font-size: 13px;
  font-weight: 600;
  cursor: pointer;
  font-family: inherit;
  transition: all 0.2s;
}

.editProfileBtn:hover {
  transform: translateY(-1px);
  box-shadow: 0 4px 16px rgba(124, 58, 237, 0.4);
}

/* Info rows */
.infoBox {
  background: #141820;
  border-radius: 10px;
  margin: 16px;
  padding: 16px;
  display: flex;
  flex-direction: column;
  gap: 16px;
}

.infoRow {
  display: flex;
  justify-content: space-between;
  align-items: center;
}

.infoLabel {
  font-size: 10px;
  font-weight: 700;
  color: #555a6e;
  text-transform: uppercase;
  letter-spacing: 0.06em;
  margin-bottom: 4px;
}

.infoValue {
  font-size: 14px;
  color: #e4e6eb;
}

.revealText {
  color: #7c3aed;
  font-size: 13px;
  cursor: pointer;
  font-weight: 500;
  transition: color 0.15s;
}

.revealText:hover {
  color: #a78bfa;
}

.editBtn {
  background: #1a1f2e;
  color: #e4e6eb;
  border: 1px solid rgba(255, 255, 255, 0.06);
  padding: 6px 14px;
  border-radius: 8px;
  font-size: 13px;
  font-weight: 500;
  cursor: pointer;
  font-family: inherit;
  transition: all 0.15s;
}

.editBtn:hover {
  background: #1f2538;
  border-color: rgba(255, 255, 255, 0.1);
}

/* Sections */
.sectionContainer {
  margin-top: 36px;
}

.sectionTitle {
  font-size: 16px;
  font-weight: 700;
  color: #e4e6eb;
  margin-bottom: 16px;
}

.blockTitle {
  font-size: 14px;
  font-weight: 600;
  color: #e4e6eb;
  margin-bottom: 6px;
}

.blockDesc {
  font-size: 13px;
  color: #8b8fa3;
  margin-bottom: 14px;
  line-height: 1.5;
}

.primaryBtn {
  background: linear-gradient(135deg, #7c3aed, #3b82f6);
  color: #fff;
  border: none;
  padding: 9px 18px;
  border-radius: 8px;
  font-size: 13px;
  font-weight: 600;
  cursor: pointer;
  font-family: inherit;
  transition: all 0.2s;
  width: fit-content;
}

.primaryBtn:hover {
  transform: translateY(-1px);
  box-shadow: 0 4px 16px rgba(124, 58, 237, 0.4);
}

.sectionDivider {
  height: 1px;
  background: rgba(255, 255, 255, 0.06);
  margin: 36px 0;
}

/* Danger buttons */
.buttonGroup {
  display: flex;
  gap: 12px;
  margin-top: 12px;
}

.dangerBtn {
  background: #ef4444;
  color: #fff;
  border: none;
  padding: 9px 18px;
  border-radius: 8px;
  font-size: 13px;
  font-weight: 600;
  cursor: pointer;
  font-family: inherit;
  transition: all 0.15s;
}

.dangerBtn:hover {
  background: #dc2626;
}

.dangerGhostBtn {
  background: transparent;
  color: #ef4444;
  border: 1px solid rgba(239, 68, 68, 0.3);
  padding: 9px 18px;
  border-radius: 8px;
  font-size: 13px;
  font-weight: 600;
  cursor: pointer;
  font-family: inherit;
  transition: all 0.15s;
}

.dangerGhostBtn:hover {
  background: rgba(239, 68, 68, 0.1);
}

/* Close */
.closeContainer {
  position: absolute;
  top: 60px;
  right: 40px;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 4px;
  cursor: pointer;
  color: #555a6e;
  transition: color 0.15s;
}

.closeContainer:hover {
  color: #e4e6eb;
}

.closeBtn {
  width: 36px;
  height: 36px;
  border-radius: 10px;
  border: 2px solid #555a6e;
  display: flex;
  align-items: center;
  justify-content: center;
  background: transparent;
  color: inherit;
  transition: all 0.2s;
}

.closeContainer:hover .closeBtn {
  border-color: #e4e6eb;
}

.escText {
  font-size: 12px;
  font-weight: 600;
}

/* Delete Confirmation Modal */
.modalOverlay {
  position: absolute;
  inset: 0;
  background: rgba(0, 0, 0, 0.7);
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 2000;
  animation: fadeIn 0.2s ease-out;
  backdrop-filter: blur(4px);
}

.modalContent {
  background: #141820;
  border: 1px solid rgba(255, 255, 255, 0.08);
  border-radius: 12px;
  padding: 24px;
  max-width: 400px;
  width: 90%;
  box-shadow: 0 8px 32px rgba(0, 0, 0, 0.5);
  animation: slideUp 0.3s cubic-bezier(0.16, 1, 0.3, 1);
}

@keyframes slideUp {
  from {
    opacity: 0;
    transform: translateY(20px);
  }

  to {
    opacity: 1;
    transform: translateY(0);
  }
}

.modalTitle {
  font-size: 18px;
  font-weight: 700;
  color: #e4e6eb;
  margin-top: 0;
  margin-bottom: 12px;
}

.modalText {
  font-size: 14px;
  color: #8b8fa3;
  margin-bottom: 24px;
  line-height: 1.5;
}

.errorText {
  color: #ef4444;
  font-size: 13px;
  margin-bottom: 16px;
  background: rgba(239, 68, 68, 0.1);
  padding: 8px 12px;
  border-radius: 6px;
  border: 1px solid rgba(239, 68, 68, 0.2);
}

.modalActions {
  display: flex;
  justify-content: flex-end;
  gap: 12px;
}

.cancelBtn {
  background: transparent;
  color: #e4e6eb;
  border: 1px solid rgba(255, 255, 255, 0.1);
  padding: 9px 18px;
  border-radius: 8px;
  font-size: 13px;
  font-weight: 600;
  cursor: pointer;
  transition: all 0.2s;
  font-family: inherit;
}

.cancelBtn:hover:not(:disabled) {
  background: rgba(255, 255, 255, 0.05);
  border-color: rgba(255, 255, 255, 0.2);
}

.cancelBtn:disabled {
  opacity: 0.5;
  cursor: not-allowed;
}

.cancelLinkBtn {
  background: transparent;
  color: #e4e6eb;
  border: none;
  padding: 9px 18px;
  border-radius: 8px;
  font-size: 13px;
  font-weight: 500;
  cursor: pointer;
  transition: all 0.2s;
  font-family: inherit;
}

.cancelLinkBtn:hover:not(:disabled) {
  text-decoration: underline;
}

.cancelLinkBtn:disabled {
  opacity: 0.5;
  cursor: not-allowed;
}

.confirmDeleteBtn {
  background: #ef4444;
  color: #fff;
  border: none;
  padding: 9px 18px;
  border-radius: 8px;
  font-size: 13px;
  font-weight: 600;
  cursor: pointer;
  transition: all 0.2s;
  font-family: inherit;
}

.confirmDeleteBtn:hover:not(:disabled) {
  background: #dc2626;
  transform: translateY(-1px);
  box-shadow: 0 4px 12px rgba(239, 68, 68, 0.3);
}

.confirmDeleteBtn:disabled {
  opacity: 0.5;
  cursor: not-allowed;
  transform: none;
  box-shadow: none;
}

/* Success Toast */
.successToast {
  position: absolute;
  top: 40px;
  left: 50%;
  transform: translateX(-50%);
  background: #10b981;
  color: #fff;
  padding: 12px 24px;
  border-radius: 8px;
  font-size: 14px;
  font-weight: 600;
  display: flex;
  align-items: center;
  gap: 10px;
  z-index: 3000;
  box-shadow: 0 8px 32px rgba(16, 185, 129, 0.3);
  animation: toastSlideDown 0.3s cubic-bezier(0.16, 1, 0.3, 1);
}

@keyframes toastSlideDown {
  from {
    opacity: 0;
    transform: translate(-50%, -20px);
  }

  to {
    opacity: 1;
    transform: translate(-50%, 0);
  }
}

/* Edit Modal Forms */
.formGroup {
  margin-bottom: 20px;
  text-align: left;
}

.inputLabel {
  display: block;
  font-size: 10px;
  font-weight: 700;
  color: #8b8fa3;
  text-transform: uppercase;
  letter-spacing: 0.08em;
  margin-bottom: 8px;
}

.inputField {
  width: 100%;
  background: #0d1017;
  border: 1px solid rgba(255, 255, 255, 0.08);
  border-radius: 6px;
  color: #e4e6eb;
  padding: 10px 14px;
  font-size: 14px;
  outline: none;
  font-family: inherit;
  transition: border-color 0.2s, box-shadow 0.2s;
  box-sizing: border-box;
}

.inputField:focus {
  border-color: #5865f2;
}

.confirmEditBtn {
  background: #5865f2;
  color: #fff;
  border: none;
  padding: 9px 18px;
  border-radius: 8px;
  font-size: 13px;
  font-weight: 600;
  cursor: pointer;
  transition: all 0.2s;
  font-family: inherit;
}

.confirmEditBtn:hover:not(:disabled) {
  background: #4752c4;
  box-shadow: 0 4px 12px rgba(88, 101, 242, 0.3);
}

.confirmEditBtn:disabled {
  opacity: 0.5;
  cursor: not-allowed;
  transform: none;
  box-shadow: none;
}

