import { BrowserRouter as Router, Routes, Route, Navigate, useParams, useNavigate } from "react-router-dom";
import { useEffect, useState } from "react";
import { useAuth } from "./context/AuthContext";
import OAuthCallback from "./pages/OAuthCallback";
import Landing from "./pages/Landing";
import Login from "./pages/Login";
import Signup from "./pages/Signup";
import App from "./pages/AppPage";
import ProtectedRoute from "./components/ProtectedRoute";
import "./index.css";

/**
 * GuestRoute – if the user already has a token, redirect to /app
 */
function GuestRoute({ children }) {
  const { token } = useAuth();
  if (token) {
    return <Navigate to="/app" replace />;
  }
  return children;
}

/**
 * InvitePage – handles /invite/:code
 * If logged in → auto-join the server and redirect to /app
 * If not logged in → redirect to /login, then they can paste the link in the Join modal
 */
function InvitePage() {
  const { code } = useParams();
  const navigate = useNavigate();
  const { token } = useAuth();
  const [status, setStatus] = useState("Joining server...");

  useEffect(() => {
    if (!token) {
      navigate("/login", { replace: true });
      return;
    }

    const joinServer = async () => {
      try {
        const res = await fetch(`http://localhost:8000/api/servers/invite/${code}/join`, {
          method: "POST",
          headers: {
            "Content-Type": "application/json",
            Authorization: `Bearer ${token}`,
          },
        });

        const data = await res.json();
        if (res.ok) {
          navigate("/app", { replace: true });
        } else {
          setStatus(data.error || "Failed to join server");
        }
      } catch (err) {
        setStatus("Could not connect to server");
      }
    };

    joinServer();
  }, [code, token, navigate]);

  return (
    <div style={{
      minHeight: '100vh',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      background: '#313338',
      color: '#f2f3f5',
      fontFamily: "'Outfit', 'Noto Sans', sans-serif",
      fontSize: '1.2rem',
    }}>
      {status}
    </div>
  );
}

function AppRouter() {
  return (
    <Router>
      <Routes>
        <Route path="/" element={<Landing />} />
        <Route path="/login" element={
          <GuestRoute><Login /></GuestRoute>
        } />
        <Route path="/signup" element={
          <GuestRoute><Signup /></GuestRoute>
        } />
        <Route path="/app" element={
          <ProtectedRoute><App /></ProtectedRoute>
        } />
        <Route path="/oauth-callback" element={<OAuthCallback />} />
        <Route path="/invite/:code" element={<InvitePage />} />
        <Route path="*" element={<Navigate to="/" />} />
      </Routes>
    </Router>
  );
}

export default AppRouter;

import { Link } from "react-router-dom";
import Logo from "./Logo";
import styles from "./AuthForm.module.css";

const GOOGLE_AUTH_URL = "http://localhost:8000/api/auth/google";

export default function AuthForm({
  title, subtitle, fields,
  submitLabel, onSubmit,
  footerText, footerLink, footerLinkText,
  error, loading, showOAuth = true,
}) {
  const handleSubmit = (e) => {
    e.preventDefault();
    const formData = {};
    fields.forEach(f => { formData[f.name] = e.target[f.name].value; });
    onSubmit(formData);
  };

  const handleGoogleLogin = () => {
    window.location.href = GOOGLE_AUTH_URL;
  };

  return (
    <div className={styles.wrapper}>
      {/* Twinkling stars background */}
      <div className={styles.starField}>
        {Array.from({ length: 25 }).map((_, i) => (
          <div key={i} className={styles.star} style={{
            left: `${Math.random() * 100}%`,
            top: `${Math.random() * 100}%`,
            animationDelay: `${Math.random() * 3}s`,
            width: `${Math.random() * 3 + 1}px`,
            height: `${Math.random() * 3 + 1}px`,
          }} />
        ))}
      </div>

      <div className={styles.card}>
        <Logo size={28} light />
        <h1 className={styles.title}>{title}</h1>
        <p className={styles.subtitle}>{subtitle}</p>

        {error && (
          <div className={styles.errorBox}>
            <span className={styles.errorIcon}>⚠</span>
            {error}
          </div>
        )}

        <form onSubmit={handleSubmit} className={styles.form}>
          {fields.map((field) => (
            <div className={styles.field} key={field.name}>
              <label className={styles.label}>{field.label}</label>
              <input
                className={styles.input}
                type={field.type || "text"}
                name={field.name}
                placeholder={field.placeholder}
                required
              />
            </div>
          ))}
          <button type="submit" className={styles.submitBtn} disabled={loading}>
            {loading && <span className={styles.spinner} />}
            {loading ? "Please wait…" : submitLabel}
          </button>
        </form>

        {showOAuth && (
          <div className={styles.oauthSection}>
            <div className={styles.oauthDivider}>
              <span>or</span>
            </div>
            <button
              type="button"
              className={styles.googleBtn}
              onClick={handleGoogleLogin}
            >
