            Authorization: `Bearer ${token}`
            // Do NOT set Content-Type; FormData sets it with boundary
          },
          body: formData
        });

        if (!uploadRes.ok) {
          const errData = await uploadRes.json();
          alert(`Attachment upload failed: ${errData.error}`);
          setIsSending(false);
